const checkpoints = [];

function parseDateSafe(v) {
  const d = new Date(v);
  return isNaN(d.getTime()) ? null : d;
}

const briefings = JSON.parse(localStorage.getItem('briefings') || '[]');
const briefingSettings = JSON.parse(localStorage.getItem('briefing_settings') || '[]');
const briefingItems = JSON.parse(localStorage.getItem('briefing_items') || '[]');
const weatherReports = JSON.parse(localStorage.getItem('weather_reports') || '[]');
const airports = JSON.parse(localStorage.getItem('airports') || '[]');

const kjfk = airports.find(a => a && a.icaoCode === 'KJFK');
const briefing = briefings.find(b => b && b.title === "Today's Briefing") || null;

let currentMetar = null;
let currentTaf = null;

if (kjfk) {
  const reportsForKjfk = weatherReports.filter(w => w && w.airportId === kjfk.id);
  const metars = reportsForKjfk.filter(w => w.reportType === 'metar');
  const tafs = reportsForKjfk.filter(w => w.reportType === 'taf');

  metars.sort((a, b) => {
    const da = parseDateSafe(a.observationTime || a.createdAt);
    const db = parseDateSafe(b.observationTime || b.createdAt);
    if (!da && !db) return 0;
    if (!da) return 1;
    if (!db) return -1;
    return db - da; // newest first
  });
  tafs.sort((a, b) => {
    const da = parseDateSafe(a.validFrom || a.createdAt);
    const db = parseDateSafe(b.validFrom || b.createdAt);
    if (!da && !db) return 0;
    if (!da) return 1;
    if (!db) return -1;
    return db - da; // newest first
  });

  currentMetar = metars[0] || null;
  currentTaf = tafs[0] || null;
}

let metarItem = null;
let tafItem = null;

if (briefing && currentMetar && currentTaf) {
  const itemsForBriefing = briefingItems.filter(bi => bi && bi.briefingId === briefing.id && bi.itemType === 'weather_report');
  metarItem = itemsForBriefing.find(bi => bi.weatherReportId === currentMetar.id) || null;
  tafItem = itemsForBriefing.find(bi => bi.weatherReportId === currentTaf.id) || null;
}

// CP1 (0.4): Today's Briefing contains BOTH the current KJFK METAR and current KJFK TAF as weather_report items
const hasBothCurrent = !!(briefing && currentMetar && currentTaf && metarItem && tafItem);
checkpoints.push({ passed: hasBothCurrent, weight: 0.4 });

// CP2 (0.3): Today's Briefing settings use knots & statute miles units
let unitsOk = false;
if (briefing) {
  const settings = briefingSettings.find(s => s && s.briefingId === briefing.id) || null;
  unitsOk = !!(settings && settings.unitsPreset === 'knots_statute_miles');
}
checkpoints.push({ passed: unitsOk, weight: 0.3 });

// CP3 (0.3): METAR item is ordered above TAF item in the briefing (lower orderIndex)
let orderOk = false;
if (metarItem && tafItem && typeof metarItem.orderIndex === 'number' && typeof tafItem.orderIndex === 'number') {
  orderOk = metarItem.orderIndex < tafItem.orderIndex;
}
checkpoints.push({ passed: orderOk, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function toRad(deg) { return (deg * Math.PI) / 180; }
function haversineNm(lat1, lon1, lat2, lon2) {
  if (typeof lat1 !== 'number' || typeof lon1 !== 'number' || typeof lat2 !== 'number' || typeof lon2 !== 'number') return null;
  const R_nm = 3440.065;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
            Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) *
            Math.sin(dLon / 2) * Math.sin(dLon / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R_nm * c;
}

const airports = JSON.parse(localStorage.getItem('airports') || '[]');
const routes = JSON.parse(localStorage.getItem('routes') || '[]');
const routeLists = JSON.parse(localStorage.getItem('route_lists') || '[]');

const departure = airports.find(a => a && a.icaoCode === 'KSFO');

let candidateResults = [];
if (departure) {
  airports.forEach(a => {
    if (!a || a.id === departure.id) return;
    const runwayLen = typeof a.longestRunwayLengthFt === 'number' ? a.longestRunwayLengthFt : 0;
    if (runwayLen < 4500) return;
    const dist = haversineNm(departure.latitude, departure.longitude, a.latitude, a.longitude);
    if (dist === null || dist > 120) return;
    candidateResults.push({ airport: a, distanceNm: dist });
  });
}

let bestAirports = [];
if (candidateResults.length > 0) {
  const maxRating = candidateResults.reduce((max, r) => {
    const rating = typeof r.airport.userRating === 'number' ? r.airport.userRating : 0;
    return rating > max ? rating : max;
  }, 0);
  bestAirports = candidateResults.filter(r => (r.airport.userRating || 0) === maxRating).map(r => r.airport);
}

let qualifyingRoutes = [];
if (departure && bestAirports.length > 0) {
  const bestIds = bestAirports.map(a => a.id);
  qualifyingRoutes = routes.filter(r => {
    if (!r) return false;
    const nameOk = r.name === 'KSFO cross-country #1';
    const rulesOk = r.flightRules === 'vfr';
    const depOk = r.departureAirportId === departure.id;
    const destOk = bestIds.includes(r.destinationAirportId);
    let distOk = false;
    let runwayOk = false;
    const dest = airports.find(a => a && a.id === r.destinationAirportId) || null;
    if (dest) {
      const dist = haversineNm(departure.latitude, departure.longitude, dest.latitude, dest.longitude);
      distOk = dist !== null && dist <= 120.0001;
      runwayOk = typeof dest.longestRunwayLengthFt === 'number' && dest.longestRunwayLengthFt >= 4500;
    }
    return nameOk && rulesOk && depOk && destOk && distOk && runwayOk;
  });
}

// CP1 (0.7): At least one route matches name, VFR, departs KSFO, and goes to a highest-rated qualifying airport within 120 NM with runway >= 4,500 ft
const hasBestRoute = qualifyingRoutes.length > 0;
checkpoints.push({ passed: hasBestRoute, weight: 0.7 });

// CP2 (0.3): That route is saved into a route list named 'Practice Flights'
let inPracticeFlights = false;
if (hasBestRoute) {
  inPracticeFlights = qualifyingRoutes.some(r => {
    const list = routeLists.find(l => l && l.id === r.routeListId) || null;
    return !!(list && list.name === 'Practice Flights');
  });
}
checkpoints.push({ passed: inPracticeFlights, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseDateSafe(v) {
  const d = new Date(v);
  return isNaN(d.getTime()) ? null : d;
}

const courses = JSON.parse(localStorage.getItem('courses') || '[]');
const items = JSON.parse(localStorage.getItem('training_plan_items') || '[]');

const qualifyingCourses = courses.filter(c => {
  if (!c) return false;
  if (c.category !== 'IFR ground school') return false;
  if (typeof c.priceUsd !== 'number' || c.priceUsd >= 150) return false;
  if ((c.rating || 0) < 4.5) return false;
  if (typeof c.totalDurationHours !== 'number' || c.totalDurationHours < 8) return false;
  return true;
});

let itemsWithQualifyingCourseAndGoal = [];
if (items.length && courses.length) {
  itemsWithQualifyingCourseAndGoal = items.filter(item => {
    const course = courses.find(c => c && c.id === item.courseId) || null;
    if (!course) return false;
    const basicQual = qualifyingCourses.some(q => q.id === course.id);
    if (!basicQual) return false;
    const goalText = (item.goal || '').trim().toLowerCase();
    const goalOk = goalText === 'ifr rating';
    const d = parseDateSafe(item.targetCompletionDate);
    const yearOk = !!d && d.getUTCFullYear() === 2026;
    return goalOk && yearOk;
  });
}

// CP1 (0.4): Training plan contains at least one item using a qualifying IFR ground course, with goal 'IFR Rating' and target completion year 2026
const hasQualifyingItem = itemsWithQualifyingCourseAndGoal.length > 0;
checkpoints.push({ passed: hasQualifyingItem, weight: 0.4 });

// CP2 (0.6): The chosen course is the CHEAPEST among all qualifying IFR ground school courses
let cheapestCorrect = false;
if (qualifyingCourses.length > 0 && hasQualifyingItem) {
  const cheapestPrice = qualifyingCourses.reduce((min, c) => c.priceUsd < min ? c.priceUsd : min, qualifyingCourses[0].priceUsd);
  cheapestCorrect = itemsWithQualifyingCourseAndGoal.some(item => {
    const c = courses.find(cc => cc && cc.id === item.courseId) || null;
    return !!(c && c.priceUsd === cheapestPrice);
  });
}
checkpoints.push({ passed: cheapestCorrect, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseDateSafe(v) {
  const d = new Date(v);
  return isNaN(d.getTime()) ? null : d;
}

const events = JSON.parse(localStorage.getItem('events') || '[]');
const registrations = JSON.parse(localStorage.getItem('registrations') || '[]');

const qualifyingEvents = events.filter(e => {
  if (!e) return false;
  if (e.eventType !== 'webinar') return false;
  if (e.topic !== 'ifr_weather') return false;
  const d = parseDateSafe(e.startDateTime);
  if (!d) return false;
  const year = d.getUTCFullYear();
  const month = d.getUTCMonth() + 1; // 1-12
  return year === 2026 && month === 10;
});

let earliestEvent = null;
let earliestTime = null;
qualifyingEvents.forEach(e => {
  const d = parseDateSafe(e.startDateTime);
  if (!d) return;
  if (!earliestTime || d < earliestTime) {
    earliestTime = d;
    earliestEvent = e;
  }
});

const baseRegistrations = registrations.filter(r => {
  if (!r) return false;
  const ev = qualifyingEvents.find(e => e.id === r.eventId) || null;
  if (!ev) return false;
  return r.notificationChannel === 'site_notifications_only' && r.reminderOffsetDays === 1;
});

// CP1 (0.5): Registered for some IFR weather webinar in Oct 2026 with site notifications only and 1-day reminder
const hasQualifyingRegistration = baseRegistrations.length > 0;
checkpoints.push({ passed: hasQualifyingRegistration, weight: 0.5 });

// CP2 (0.5): Registration is specifically for the EARLIEST qualifying October 2026 IFR weather webinar
let earliestCorrect = false;
if (earliestEvent && hasQualifyingRegistration) {
  earliestCorrect = baseRegistrations.some(r => r.eventId === earliestEvent.id);
}
checkpoints.push({ passed: earliestCorrect, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseDateSafe(v) {
  const d = new Date(v);
  return isNaN(d.getTime()) ? null : d;
}

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const readingLists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const readingListItems = JSON.parse(localStorage.getItem('reading_list_items') || '[]');

const term = 'class b airspace';

const qualifyingArticles = articles.filter(a => {
  if (!a) return false;
  const parts = [];
  if (a.title) parts.push(a.title);
  if (a.summary) parts.push(a.summary);
  if (a.content) parts.push(a.content);
  if (Array.isArray(a.topicTags)) parts.push(a.topicTags.join(' '));
  const haystack = parts.join(' ').toLowerCase();
  if (!haystack.includes(term)) return false;
  const d = parseDateSafe(a.publishedAt);
  if (!d) return false;
  const year = d.getUTCFullYear();
  if (year < 2022) return false;
  if (typeof a.readingTimeMinutes !== 'number' || a.readingTimeMinutes > 15) return false;
  return true;
});

qualifyingArticles.sort((a, b) => (b.popularityScore || 0) - (a.popularityScore || 0));
const targetArticles = qualifyingArticles.slice(0, 3);

const list = readingLists.find(l => l && l.name === 'Checkride Prep') || null;
let savedCount = 0;

if (list && targetArticles.length > 0) {
  const listItems = readingListItems.filter(i => i && i.readingListId === list.id);
  const savedIds = listItems.map(i => i.articleId);
  savedCount = targetArticles.filter(a => savedIds.includes(a.id)).length;
}

// CP1-3: Number of correct target articles saved to 'Checkride Prep'
[1, 2, 3].forEach((n, idx) => {
  const weight = idx === 0 ? 0.34 : 0.33; // 0.34 + 0.33 + 0.33 = 1.0
  checkpoints.push({ passed: savedCount >= n, weight });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const schools = JSON.parse(localStorage.getItem('flight_schools') || '[]');
const aircraftList = JSON.parse(localStorage.getItem('aircraft') || '[]');
const preferredList = JSON.parse(localStorage.getItem('preferred_trainers') || '[]');
const comparisonSet = JSON.parse(localStorage.getItem('aircraft_comparison_set') || '[]');

function isDenverAreaSchool(s) {
  return !!(s && s.state === 'CO' && typeof s.rating === 'number' && s.rating >= 4.0);
}

function isC172Candidate(a) {
  if (!a) return false;
  if (!a.isIfrCapable) return false;
  if (typeof a.hourlyWetRateUsd !== 'number' || a.hourlyWetRateUsd > 180) return false;
  if (a.make !== 'Cessna') return false;
  return typeof a.model === 'string' && a.model.indexOf('172') !== -1;
}

function isPiperArcherCandidate(a) {
  if (!a) return false;
  if (!a.isIfrCapable) return false;
  if (typeof a.hourlyWetRateUsd !== 'number' || a.hourlyWetRateUsd > 180) return false;
  if (a.make !== 'Piper') return false;
  const model = (a.model || '').toLowerCase();
  const name = (a.name || '').toLowerCase();
  return model.includes('archer') || name.includes('archer');
}

const preferred = preferredList.length ? preferredList[preferredList.length - 1] : null;
const selectedAircraft = preferred ? aircraftList.find(a => a && a.id === preferred.aircraftId) : null;
const selectedSchool = selectedAircraft ? schools.find(s => s && s.id === selectedAircraft.flightSchoolId) : null;

// CP1 (0.4): Preferred trainer is an IFR-capable C172 or Piper Archer ≤$180/hr at a Denver-area (CO) flight school rated ≥4.0
const baseOk = !!(selectedAircraft && selectedSchool && isDenverAreaSchool(selectedSchool) && (isC172Candidate(selectedAircraft) || isPiperArcherCandidate(selectedAircraft)));
checkpoints.push({ passed: baseOk, weight: 0.4 });

// CP2 (0.6): Within that school, the preferred trainer follows the rule: lower hourly wet rate wins; if equal, choose the one listed higher in the comparison set
let ruleOk = false;
if (selectedSchool && isDenverAreaSchool(selectedSchool)) {
  const fleet = aircraftList.filter(a => a && a.flightSchoolId === selectedSchool.id);
  const c172 = fleet.find(isC172Candidate) || null;
  const archer = fleet.find(isPiperArcherCandidate) || null;
  if (c172 && archer) {
    let choice = null;
    if (c172.hourlyWetRateUsd < archer.hourlyWetRateUsd) {
      choice = c172;
    } else if (archer.hourlyWetRateUsd < c172.hourlyWetRateUsd) {
      choice = archer;
    } else {
      const idxC = comparisonSet.indexOf(c172.id);
      const idxA = comparisonSet.indexOf(archer.id);
      const cIndex = idxC === -1 ? Infinity : idxC;
      const aIndex = idxA === -1 ? Infinity : idxA;
      if (cIndex < aIndex) choice = c172;
      else if (aIndex < cIndex) choice = archer;
    }
    if (choice && selectedAircraft && selectedAircraft.id === choice.id) {
      ruleOk = true;
    }
  }
}
checkpoints.push({ passed: ruleOk, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseDateSafe(v) {
  const d = new Date(v);
  return isNaN(d.getTime()) ? null : d;
}

const examiners = JSON.parse(localStorage.getItem('medical_examiners') || '[]');
const contacts = JSON.parse(localStorage.getItem('contacts') || '[]');
const groups = JSON.parse(localStorage.getItem('contact_groups') || '[]');

const qualifyingExaminers = examiners.filter(e => {
  if (!e) return false;
  if (!e.offersClass1Medicals) return false;
  if (!e.weekdayAvailabilityBefore6pm) return false;
  if (typeof e.distanceFromSearchZipMiles !== 'number') return false;
  return e.distanceFromSearchZipMiles <= 30;
});

let earliestExaminer = null;
let earliestTime = null;
qualifyingExaminers.forEach(e => {
  const d = parseDateSafe(e.nextAvailableAppointment);
  if (!d) return;
  if (!earliestTime || d < earliestTime) {
    earliestTime = d;
    earliestExaminer = e;
  }
});

const group = groups.find(g => g && g.name === 'Medical Contacts') || null;
let qualifyingContacts = [];
if (group) {
  const contactsInGroup = contacts.filter(c => c && c.groupId === group.id && c.contactType === 'medical_examiner');
  qualifyingContacts = contactsInGroup.filter(c => qualifyingExaminers.some(e => e.id === c.medicalExaminerId));
}

// CP1 (0.4): 'Medical Contacts' group contains at least one contact for an AME that meets all distance/Class 1/before-6pm criteria
const hasQualifyingContact = qualifyingContacts.length > 0;
checkpoints.push({ passed: hasQualifyingContact, weight: 0.4 });

// CP2 (0.6): The saved contact is specifically for the earliest-available qualifying AME
let earliestCorrect = false;
if (earliestExaminer && hasQualifyingContact) {
  earliestCorrect = qualifyingContacts.some(c => c.medicalExaminerId === earliestExaminer.id);
}
checkpoints.push({ passed: earliestCorrect, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const categories = JSON.parse(localStorage.getItem('forum_categories') || '[]');
const threads = JSON.parse(localStorage.getItem('forum_threads') || '[]');
const forumTags = JSON.parse(localStorage.getItem('forum_tags') || '[]');
const threadTags = JSON.parse(localStorage.getItem('thread_tags') || '[]');
const notificationSettings = JSON.parse(localStorage.getItem('thread_notification_settings') || '[]');

const landingsCategory = categories.find(c => c && (c.name === 'Landings' || c.id === 'landings')) || null;
const landingsCategoryId = landingsCategory ? landingsCategory.id : null;
const targetTitle = 'Short-field landing tips for Cessna 172';

let hasBasicThread = false;
let hasFullThread = false;

if (landingsCategoryId) {
  const candidates = threads.filter(t => t && t.categoryId === landingsCategoryId && t.title === targetTitle);
  candidates.forEach(t => {
    const body = (t.body || '').toString();
    const sentenceCount = body.split(/[.!?]/).filter(s => s.trim().length > 0).length;
    const basicOk = sentenceCount >= 2;
    if (basicOk) hasBasicThread = true;

    const links = threadTags.filter(tt => tt && tt.threadId === t.id);
    const tagNames = links
      .map(link => {
        const tag = forumTags.find(ft => ft && ft.id === link.tagId) || null;
        return tag ? tag.name : null;
      })
      .filter(Boolean);
    const uniqueTagNames = Array.from(new Set(tagNames));
    const requiredTags = ['short-field', 'landing', 'C172'];
    const hasAllRequired = requiredTags.every(req => uniqueTagNames.includes(req));
    const noExtra = uniqueTagNames.length === requiredTags.length;

    const notif = notificationSettings.find(n => n && n.threadId === t.id) || null;
    const notifOk = !!(notif && notif.notificationChannel === 'site_notifications_only');

    if (basicOk && hasAllRequired && noExtra && notifOk) {
      hasFullThread = true;
    }
  });
}

// CP1 (0.5): A thread with the correct title exists in 'Landings' category and has a body of at least two sentences
checkpoints.push({ passed: hasBasicThread, weight: 0.5 });

// CP2 (0.5): That thread also has exactly the three required tags and site-only notifications for replies
checkpoints.push({ passed: hasFullThread, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
